import json
from collections import defaultdict

cases_result = locals()['var_functions.query_db:0']
order_items_result = locals()['var_functions.query_db:2']

print('Loading data...')

secure_order_item_ids = set()
for item in order_items_result:
    order_item_id = item['Id']
    if order_item_id.startswith('#'):
        order_item_id = order_item_id[1:]
    secure_order_item_ids.add(order_item_id)

print('Found order items: ' + str(len(secure_order_item_ids)))

secure_cases = []
for case in cases_result:
    case_order_item_id = case['orderitemid__c']
    if not case_order_item_id:
        continue
    if case_order_item_id.startswith('#'):
        case_order_item_id = case_order_item_id[1:]

    if case_order_item_id in secure_order_item_ids:
        secure_cases.append(case)

print('Found cases: ' + str(len(secure_cases)))

monthly_counts = defaultdict(int)
month_names = {'06': 'June', '07': 'July', '08': 'August', '09': 'September', '10': 'October', '11': 'November', '12': 'December', '01': 'January', '02': 'February', '03': 'March', '04': 'April'}

for case in secure_cases:
    created_date = case['createddate']
    date_part = created_date.split('T')[0]
    month_num = date_part.split('-')[1]

    if date_part >= '2020-06-01' and date_part <= '2021-04-10':
        if month_num in month_names:
            monthly_counts[month_num] += 1

output = []
for month_num in sorted(monthly_counts.keys()):
    output.append({'month': month_names[month_num], 'count': monthly_counts[month_num]})

print('Monthly counts:')
for item in output:
    print(item['month'] + ': ' + str(item['count']))

result = None
if len(output) > 0:
    max_count = max(item['count'] for item in output)
    if len(output) > 1:
        others = [item['count'] for item in output if item['count'] != max_count]
        avg_others = sum(others) / len(others) if others else 0
        if max_count > avg_others * 1.5:
            for item in output:
                if item['count'] == max_count:
                    result = item['month']
    else:
        result = output[0]['month']

print('Result month: ' + str(result))

result_data = {'month': result}
print('__RESULT__:')
print(json.dumps(result_data))

